USE P21;
SET NOCOUNT ON;
SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
DECLARE @d nvarchar(max) = (SELECT definition FROM sys.sql_modules WHERE object_id=OBJECT_ID('dbo.p21_create_container_receipt_records'));
;WITH n AS (
  SELECT 1 AS chunk_no, SUBSTRING(@d,1,3500) AS chunk_text UNION ALL
  SELECT 2, SUBSTRING(@d,3501,3500) UNION ALL
  SELECT 3, SUBSTRING(@d,7001,3500) UNION ALL
  SELECT 4, SUBSTRING(@d,10501,3500) UNION ALL
  SELECT 5, SUBSTRING(@d,14001,3500) UNION ALL
  SELECT 6, SUBSTRING(@d,17501,3500) UNION ALL
  SELECT 7, SUBSTRING(@d,21001,3500) UNION ALL
  SELECT 8, SUBSTRING(@d,24501,3500)
)
SELECT result_set='p21_create_container_receipt_records_definition', chunk_no=CONVERT(varchar(20), chunk_no), chunk_text FROM n WHERE chunk_text IS NOT NULL AND LEN(chunk_text)>0 ORDER BY chunk_no;
